SELECT a.area_id
FROM areas a
JOIN income_data i ON a.area_id = i.area_id
JOIN crime_data c ON a.area_id = c.area_id
WHERE i.mean_income = (
    SELECT MAX(mean_income) FROM income_data
)
AND i.per_capita_income = (
    SELECT MAX(per_capita_income) FROM income_data
)
AND c.total_crime = (
    SELECT MAX(total_crime) FROM crime_data
)
AND a.population_density = (
    SELECT MAX(population_density) FROM areas
);

SELECT high_bracket_income
FROM high_bracket_income
WHERE area_id = 1;

SELECT area_id, MAX(high_bracket_income) 
FROM high_bracket_income 
GROUP BY area_id;

SELECT a.area_name, a.population_density
FROM areas a
INNER JOIN crime_data c ON a.area_id = c.area_id
WHERE c.total_crime > (
    SELECT AVG(total_crime) FROM crime_data
)
AND a.population_density > (
    SELECT AVG(population_density) FROM areas
);

SELECT areas.area_name, high_bracket_income.high_bracket_income 
FROM areas 
INNER JOIN high_bracket_income ON areas.area_id = high_bracket_income.area_id;

SELECT a.area_name, c.property_crime
FROM areas a
JOIN crime_data c ON a.area_id = c.area_id
WHERE c.property_crime > (
    SELECT AVG(property_crime) FROM crime_data
);
